process.env.DEBUG = '*';

var async = require('async'),

debug = require('debug'),

log = debug('main'),

fs = require('fs'),

locationUids = [],
eventUids = [],
reviewUids = [],
gottenEvent,
createdReview,
listedEvents,

cbm,

run = function() {
  
  async.series([
    loadLib,
    clearEvents,
    clearLocations,
    clearReviews,
    createLocation('./fixtures/locations/rivoli59.json'),
    getNewLocation,
    createEvent('./fixtures/events/les-particulieres-2014.json'),
    getNewEvent,
    listNewEvent,
    getAndListCompare,
    createReview('./fixtures/reviews/chez-nous.json'),
    getNewReview
  ], function(err, results) {

    if (err) {

      log('something went wrong:');

      log(err);

    } else {

      log('done.');

    }

  });

},

loadLib = function(cb) {

  log('load cibulModel library');

  var dbConfig = {
    host: 'localhost',
    database: 'cibultest',
    user: 'root',
    password: 'grut'
  },

  s3Config = {
    key: 'AKIAIBU4IMFWJUDASWYA',
    secret: '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',
    bucket: 'cibultest',
    staticBucket: 'cibulstatic'
  };

  cbm = require('../lib/cibulModel')(dbConfig, s3Config);

  log('lib loaded');

  cb();

},

getNewLocation = function(cb) {

  log('retrieve latest location by uid');

  cbm.locations().get({uid: locationUids[0]}, handleResponse(cb, 'retrieved new location'));

},

getNewEvent = function(cb) {

  log('retrieve latest event by uid');

  cbm.events().get({uid: eventUids[0]}, function(err, result) {

    if (err) return cb(err);

    gottenEvent = result;

    log('retrieved newest event');

    cb();

  });

},

listNewEvent = function(cb) {

  log('retrieve all events by list');

  cbm.events().list(function(err, result) {

    if (err) return cb(err);

    if (!result.length) return cb('Did not return anything.');

    log('retrieved events list');

    listedEvents = result;

    cb();

  });

},

getAndListCompare = function(cb) {

  log('compare event fetched by get and by list');

  if (JSON.stringify(listedEvents[0])!==JSON.stringify(gottenEvent)) {

    return cb('event info is different');

  }

  log('event structure is the same');

  cb();

},

getNewReview = function(cb) {

  log('get newly created review');

  cbm.reviews().get({ uid: createdReview.uid }, function(err, result) {

    if (err) return cb(err);

    if (createdReview.title !== result.title) return cb('review has a different title');

    log('retrieved review successful (same title)');

    cb();

  });

},

createEvent = function(fixture) {

  log('create event based on fixture %s', fixture);

  return function(cb) {

    readFixture(fixture, function(err, eData) {

      if (err) return cb(err);

      eData.locations[0].uid = locationUids[0];

      eData.ownerId = 1;

      cbm.events().create(eData, function(err, result) {

        if (err) return cb(err);

        eventUids.push(result.uid);

        handleResponse(cb, 'created event %s', result.title.fr)(err, result);

      });

    });

  };

},

createLocation = function(fixture) {

  log('create location based on fixture %s', fixture);

  return function(cb) {

    readFixture(fixture, function(err, lData) {

      if (err) return cb(err);

      lData.ownerId = 1;

      cbm.locations().create(lData, function(err, result) {

        if (err) return cb(err);

        locationUids.push(result.uid);

        handleResponse(cb, 'created location %s', result.placename)(err, result);

      });

    });

  };

},

createReview = function(fixture) {

  log('create review based on fixture %s', fixture);

  return function(cb) {

    readFixture(fixture, function(err, rData) {

      if (err) return cb(err);

      rData.ownerId = 1;

      cbm.reviews().create(rData, function(err, result) {

        if (err) return cb(err);

        createdReview = rData;

        handleResponse(cb, 'created review %s', result.title)(err, result);

      });

    });

  };

},

clearLocations = function(cb) {

  log('clearing all locations in db');

  cbm.locations().clear(handleResponse(cb, 'cleared locations'));

},

clearEvents = function(cb) {

  log('clearing all events in db');

  cbm.events().clear(handleResponse(cb, 'cleared events'));

},

clearReviews = function(cb) {

  log('clearing all reviews in db');

  cbm.reviews().clear(handleResponse(cb, 'cleared reviews'));

},


/**
 * utility functions down here
 */

readFixture = function(path, cb) {

  fs.readFile(path, 'utf8', function (err,data) {

    if (err) return cb(err);

    try {

      var decodedData = JSON.parse(data);

      cb(null, decodedData);

    } catch (e) {

      cb(e);

    }

  });

},

handleResponse = function(cb, successLabel, labelValue) {

  return function(err, result) {

    if (err) return cb(err);

    if (labelValue) {

      log(successLabel, labelValue);

    } else {

      log(successLabel);

    }

    cb();

  };

};


run();